+// ProbeEntry represents a single pane probe result inside a session response.
+type ProbeEntry struct {
+	Pane           int                 `json:"pane"`
+	Responsive     bool                `json:"responsive"`
+	ProbeMethod    ProbeMethod         `json:"probe_method"`
