+func TestGetMSSearch_MissingBinary(t *testing.T) {
+	t.Setenv("PATH", "")
+
+	output, err := GetMSSearch("workflow")
+	if err != nil {
+		t.Fatalf("GetMSSearch returned error: %v", err)
+	}
+	if output.Success {
